#include <iostream>

int main()
{
    int a {};
    int b {};
    std::cin >> a >> b;
    int temp { a };
    a = b;
    b = temp;
    std::cout << "a: " << a << '\n';
    std::cout << "b: " << b << '\n';
    return 0;
}

